package com.yourapp.pythoncompiler;

import android.app.Application;
import com.yourapp.pythoncompiler.core.EnvironmentManager;
import com.yourapp.pythoncompiler.core.ProjectManager;
import com.yourapp.pythoncompiler.database.DatabaseHelper;

public class PythonCompilerApp extends Application {

    private static PythonCompilerApp instance;
    private EnvironmentManager environmentManager;
    private ProjectManager projectManager;
    private DatabaseHelper databaseHelper;

    @Override
    public void onCreate() {
        super.onCreate();
        instance = this;

        // Initialize shared resources
        databaseHelper = new DatabaseHelper(this);
        environmentManager = new EnvironmentManager(this);
        projectManager = new ProjectManager(this, databaseHelper);

        // Initialize environment (stub - replace with full logic)
        environmentManager.initializeEnvironment(status -> {
            if (status) {
                System.out.println("[INIT] Build environment ready.");
            } else {
                System.out.println("[INIT] Environment setup failed.");
            }
        });
    }

    public static PythonCompilerApp getInstance() {
        return instance;
    }

    public EnvironmentManager getEnvironmentManager() {
        return environmentManager;
    }

    public ProjectManager getProjectManager() {
        return projectManager;
    }

    public DatabaseHelper getDatabaseHelper() {
        return databaseHelper;
    }
}"}

